runner = ParametrizedRunner()
runner.register_fixture('pi', lambda: 3.14)

@runner.parametrize('val,expected', [
    (lazy_fixture('pi'), 3.14),
    (2.72, 2.72),
])
def test_vals(val, expected):
    assert val == expected

[r['passed'] for r in runner.run(test_vals)]

